import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { Plus, Search, Filter, Calendar, Tag, Edit3, Trash2, X } from 'lucide-react';
import '../styles/Despesas.css';

const Despesas = () => {
  const [despesas, setDespesas] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  
  // Estados para Edição
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [itemEditando, setItemEditando] = useState(null);

  const navigate = useNavigate();

  useEffect(() => {
    buscarDados();
  }, []);

  async function buscarDados() {
    setLoading(true);
    try {
      // Busca Despesas
      const { data: dataDesp, error: errDesp } = await supabase
        .from('compras')
        .select(`*, categorias (nome, cor)`)
        .eq('tipo_despesa', 'Gastos Variáveis')
        .order('data_compra', { ascending: false });

      // Busca Categorias para o Select do Modal
      const { data: dataCat } = await supabase.from('categorias').select('*');

      if (errDesp) throw errDesp;
      setDespesas(dataDesp || []);
      setCategorias(dataCat || []);
    } catch (error) {
      console.error("Erro:", error);
    } finally {
      setLoading(false);
    }
  }

  const handleEditar = (item) => {
    setItemEditando({ ...item });
    setIsEditModalOpen(true);
  };

  const handleSalvarEdicao = async (e) => {
    e.preventDefault();
    try {
      const { error } = await supabase
        .from('compras')
        .update({
          descricao: itemEditando.descricao,
          valor_total: itemEditando.valor_total,
          data_compra: itemEditando.data_compra,
          categoria_id: itemEditando.categoria_id,
          forma_pagamento: itemEditando.forma_pagamento
        })
        .eq('id', itemEditando.id);

      if (error) throw error;
      setIsEditModalOpen(false);
      buscarDados(); // Recarrega a lista
    } catch (error) {
      alert("Erro ao atualizar: " + error.message);
    }
  };

  const handleExcluir = async (id) => {
    if (window.confirm("Deseja realmente excluir esta despesa?")) {
      const { error } = await supabase.from('compras').delete().eq('id', id);
      if (!error) buscarDados();
    }
  };

  const formatarMoeda = (valor) => {
    return Number(valor).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  };

  const filteredDespesas = despesas.filter(d => 
    d.descricao.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="desp-premium-wrapper fade-in">
      
      {/* Top Layout: Título e Busca lado a lado, com Card de Total */}
      <div className="desp-top-layout">
        <header className="desp-panel desp-header-area">
          <div className="desp-title-area">
            <h1>Despesas</h1>
            <p>Fluxo de caixa e pagamentos à vista</p>
          </div>
          <div className="desp-search-box">
            <Search size={18} />
            <input 
              type="text" 
              placeholder="Pesquisar..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button className="btn-new-desp-desktop" onClick={() => navigate('/lancamento')}>
            <Plus size={20} /> Novo
          </button>
        </header>

        <div className="desp-panel desp-summary-card">
          <span className="summary-label">TOTAL EM GASTOS</span>
          <h2 className="summary-value">
            {formatarMoeda(filteredDespesas.reduce((acc, curr) => acc + Number(curr.valor_total), 0))}
          </h2>
        </div>
      </div>

      {/* Lista Principal */}
      <main className="desp-panel desp-list-panel">
        <div className="list-header">
          <h3>Últimos Lançamentos</h3>
          <Filter size={18} className="icon-secondary" />
        </div>

        <div className="desp-list">
          {loading ? (
            <div className="desp-status">Processando...</div>
          ) : filteredDespesas.map((item) => (
            <div key={item.id} className="desp-item-row">
              <div className="desp-item-info">
                <div className="cat-indicator" style={{ backgroundColor: item.categorias?.cor || '#4361ee' }}></div>
                <div className="desp-details">
                  <span className="desp-desc">{item.descricao}</span>
                  <div className="desp-meta">
                    <span className="meta-tag"><Calendar size={12} /> {new Date(item.data_compra).toLocaleDateString('pt-BR')}</span>
                    <span className="meta-tag"><Tag size={12} /> {item.categorias?.nome}</span>
                    <span className="method-badge">{item.forma_pagamento}</span>
                  </div>
                </div>
              </div>

              <div className="desp-item-actions-wrapper">
                <span className="desp-value">{formatarMoeda(item.valor_total)}</span>
                <div className="action-buttons">
                  <button className="btn-action" onClick={() => handleEditar(item)}><Edit3 size={16} /></button>
                  <button className="btn-action delete" onClick={() => handleExcluir(item.id)}><Trash2 size={16} /></button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </main>

      {/* MODAL DE EDIÇÃO */}
      {isEditModalOpen && (
        <div className="modal-overlay">
          <div className="edit-modal">
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px'}}>
              <h2>Editar Lançamento</h2>
              <button onClick={() => setIsEditModalOpen(false)} style={{background: 'none', border: 'none', cursor: 'pointer'}}><X /></button>
            </div>

            <form onSubmit={handleSalvarEdicao} className="edit-form-grid">
              <div className="form-group">
                <label>Descrição</label>
                <input 
                  type="text" 
                  value={itemEditando.descricao} 
                  onChange={e => setItemEditando({...itemEditando, descricao: e.target.value})}
                />
              </div>

              <div style={{display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px'}}>
                <div className="form-group">
                  <label>Valor</label>
                  <input 
                    type="number" 
                    value={itemEditando.valor_total} 
                    onChange={e => setItemEditando({...itemEditando, valor_total: e.target.value})}
                  />
                </div>
                <div className="form-group">
                  <label>Data</label>
                  <input 
                    type="date" 
                    value={itemEditando.data_compra} 
                    onChange={e => setItemEditando({...itemEditando, data_compra: e.target.value})}
                  />
                </div>
              </div>

              <div className="form-group">
                <label>Categoria</label>
                <select 
                  value={itemEditando.categoria_id} 
                  onChange={e => setItemEditando({...itemEditando, categoria_id: e.target.value})}
                >
                  {categorias.map(cat => (
                    <option key={cat.id} value={cat.id}>{cat.nome}</option>
                  ))}
                </select>
              </div>

              <div className="modal-actions">
                <button type="button" className="btn-cancel" onClick={() => setIsEditModalOpen(false)}>Cancelar</button>
                <button type="submit" className="btn-save">Salvar Alterações</button>
              </div>
            </form>
          </div>
        </div>
      )}

      <button className="desp-fab" onClick={() => navigate('/lancamento')}>
        <Plus size={24} />
      </button>
    </div>
  );
};

export default Despesas;
